.editor-word-count {
    font-size: 0.8rem;
    color: var(--text-muted);
    user-select: none;
    padding-left: 0.25rem;
}

/* ── Bar loader positioning ── */
.editor-loader-wrapper {
    height: 4px;
    flex-shrink: 0;
}

/* ── Save button ── */
.editor-save-bttn {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--editor-accent);
    color: #ffffff;
    font-weight: 650;
    cursor: pointer;
    border: none;
    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
}
.editor-save-bttn:hover {
    opacity: 0.9;
}
.editor-save-bttn:active {
    transform: scale(0.98);
}
.editor-save-bttn:focus {
    outline: none;
}
.editor-save-bttn-disabled {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--bg-pill);
    color: var(--text-muted);
    font-weight: 650;
    user-select: none;
    border: none;
    cursor: not-allowed;
}
.editor-save-bttn-disabled:focus {
    outline: none;
}

.composer-mode-btn{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    font-weight: 600;
}

/* ── Image upload icon (inside toolbar) ── */
.editor-upload-image-icon {
    padding: 0.4rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
}
.editor-upload-image-icon:hover {
    background-color: var(--bg-pill);
}

/* ── Image components ── */
.image-container {
    display: flex;
    justify-content: center;
    width: 100%;
    height: fit-content;
}
.image-wrapper {
    position: relative;
    display: flex;
    justify-content: flex-end;
    margin: 1rem 0;
    width: fit-content;
    height: fit-content;
}
.image-actions {
    position: absolute;
    display: flex;
    gap: 0.3rem;
    top: 0;
    right: 0;
    margin: 0.5rem;
    z-index: 11;
}
.image-action-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0.4rem;
    border-radius: 50%;
    cursor: pointer;
    transition: ease-in-out 0.1s;
    background-color: rgba(0, 0, 0, 0.35);
}
.image-action-btn:hover {
    background-color: rgba(0, 0, 0, 0.55);
}
.dimension-display {
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    top: -35px;
    left: 50%;
    transform: translateX(-50%);
    background-color: var(--bg-pill);
    color: var(--text-muted);
    padding: 0.4rem 0.5rem;
    white-space: nowrap;
    pointer-events: none;
    font-size: 0.8rem;
    border-radius: 4px;
}

/* ── Resize handles ── */
.southeast-side-handle {
    position: absolute;
    bottom: -4px;
    right: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: nwse-resize;
    z-index: 10;
}
.southwest-side-handle {
    position: absolute;
    bottom: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: nesw-resize;
    z-index: 10;
}
.northeast-side-handle {
    position: absolute;
    top: -4px;
    right: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: sw-resize;
    z-index: 10;
}
.northwest-side-handle {
    position: absolute;
    top: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: se-resize;
    z-index: 10;
}
.east-side-handle {
    position: absolute;
    top: 50%;
    right: -4px;
    width: 8px;
    height: 20px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateY(-50%);
    cursor: ew-resize;
    z-index: 10;
}
.south-side-handle {
    position: absolute;
    bottom: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: ns-resize;
    z-index: 10;
}
.north-side-handle {
    position: absolute;
    top: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: nw-resize;
    z-index: 10;
}

/* ── Image loading overlay ── */
.image-loading-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    background-color: rgba(0, 0, 0, 0.45);
    border-radius: 5px;
    gap: 8px;
    pointer-events: none;
}
.image-loading-spinner {
    width: 28px;
    height: 28px;
    border: 3px solid rgba(255, 255, 255, 0.2);
    border-top: 3px solid var(--editor-accent);
    border-radius: 50%;
    animation: image-spin 0.8s linear infinite;
}
@keyframes image-spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}

/* ── Full-screen image view ── */
.image-view {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    object-fit: contain;
    background: rgba(0, 0, 0, 0.7);
    z-index: 9999;
    cursor: zoom-out;
    box-sizing: border-box;
}

/* ── Mobile responsive (overrides only) ── */
@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    .toolbar {
        justify-content: center;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.35rem;
    }
    .toolbar-bttns svg,
    .is-active svg {
        width: 18px;
        height: 18px;
    }
    .toolbar-divider {
        margin: 0 4px;
        height: 16px;
    }
    .content-title-input {
        font-size: 1.35rem;
    }
    .editor-save-bttn {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-save-bttn-disabled {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
}
